const f=/^([A-Z]{4})(\d{3})([A-Z]?)$/;function C(n){return String(n??"").toUpperCase().replace(/[^A-Z0-9]/g,"")}function l(n){return C(n)}function a(n){return String(n??"").toUpperCase().replace(/[^A-Z]/g,"")}function c(n){return String(n??"").toUpperCase().replace(/[^A-Z0-9]/g,"")}function p(n){const e=l(n),r=e.match(f);if(!r)return e;const[,t,u,o]=r;return o==="H"?`${t}${u}`:e}function i(n){const e=c(n),r=e.match(/^(\d{3})H$/);return r?r[1]:e}function d(n){const e=l(n),r=e.match(f);if(!r)return e?[e]:[];const[,t,u,o]=r,s=`${t}${u}`;return o===""||o==="H"?[s,`${s}H`]:[e]}function m(n,e){const r=c(n),t=c(e);if(r===t)return!0;const u=i(r),o=i(t);return u!==o?!1:r.endsWith("H")||t.endsWith("H")}function b(n,e,r,t){const u=a(n),o=a(r);return!u||!o||u!==o?!1:m(e,t)}export{a,b,p as c,d as g,l as n};
